mapper.update:
UPDATE ai_daily_usage
SET request_count = request_count + 1,
    limit_count = #{limitCount},
    updated_at = now()
WHERE user_id = #{userId}
  AND quota_date = #{quotaDate}
  AND scope = #{scope}
  AND request_count < #{limitCount}

UPDATE ai_daily_usage
SET input_tokens = input_tokens + #{usage.inputTokens},
    output_tokens = output_tokens + #{usage.outputTokens},
    cached_tokens = cached_tokens + #{usage.cachedTokens},
    reasoning_tokens = reasoning_tokens + #{usage.reasoningTokens},
    total_tokens = total_tokens + #{usage.totalTokens},
    updated_at = now()
WHERE user_id = #{userId}
  AND quota_date = #{quotaDate}
  AND scope = #{scope}
